// Fast O(1) lookups
const wcSet = new Set(wcFootballers.map((f) => f.name.toUpperCase()))
const wcMap = new Map(wcFootballers.map((f) => [f.name.toUpperCase(), f]))
const answerCache = new Map<string, string>()

const WC_EPOCH = '03/06/2026'
const WC_SHUFFLE_SEED = 20260603

function seededShuffle<T>(arr: T[], seed: number): T[] {
	const result = [...arr]
	let s = seed >>> 0
	for (let i = result.length - 1; i > 0; i--) {
		s = (Math.imul(s, 1664525) + 1013904223) >>> 0
		const j = s % (i + 1)
		;[result[i], result[j]] = [result[j]!, result[i]!]
	}
	return result
}

const shuffledWC = seededShuffle(wcFootballers, WC_SHUFFLE_SEED)

export function getWCPuzzleNumber(dateStr: string): number {
	const [d1, m1, y1] = WC_EPOCH.split('/').map(Number)
	const [d2, m2, y2] = dateStr.split('/').map(Number)
	const epochDate = new Date(y1!, m1! - 1, d1)
	const todayDate = new Date(y2!, m2! - 1, d2)
	const diff = Math.round((todayDate.getTime() - epochDate.getTime()) / (24 * 60 * 60 * 1000))
	return diff + 1
}

export function getWCAnswerForDay(dateStr: string): string {
	if (answerCache.has(dateStr)) return answerCache.get(dateStr)!
	const idx = getWCPuzzleNumber(dateStr) - 1
	const safeIdx = ((idx % shuffledWC.length) + shuffledWC.length) % shuffledWC.length
	const answer = shuffledWC[safeIdx]?.name || ''
	answerCache.set(dateStr, answer)
	return answer
}

export function isValidWCFootballer(name: string): boolean {
	return wcSet.has(name.toUpperCase())
}

export function getWCPlayerData(name: string): WCFootballer | undefined {
	return wcMap.get(name.toUpperCase())
}

export function getWCSuggestions(query: string, limit = 8): WCFootballer[] {
	if (!query || query.length < 2) return []
	const q = query.toUpperCase()
	const startsWith = wcFootballers.filter((f) => f.name.toUpperCase().startsWith(q))
	const contains = wcFootballers.filter(
		(f) => !f.name.toUpperCase().startsWith(q) && f.name.toUpperCase().includes(q),
	)
	return [...startsWith, ...contains].slice(0, limit)
}
